import { join } from 'path';
import { homedir } from 'os';
import * as fs from 'fs';

import { resultFromThrowable } from '@agentcash/neverthrow';

const BASE_DIRECTORY = join(homedir(), '.agentcash');
const LEGACY_DIRECTORY = join(homedir(), '.x402scan-mcp');

/**
 * Auto-migrate files from ~/.x402scan-mcp/ to ~/.agentcash/
 * Copies wallet.json (and any other config) on first run after upgrade.
 * Only copies files that don't already exist in the new location.
 */
function migrateFromLegacy(): void {
  if (!fs.existsSync(LEGACY_DIRECTORY)) return;

  const result = resultFromThrowable(
    'migration',
    'fs',
    () => {
      const files = fs.readdirSync(LEGACY_DIRECTORY);
      for (const file of files) {
        // Skip logs — not worth migrating
        if (file.endsWith('.log')) continue;

        const src = join(LEGACY_DIRECTORY, file);
        const dest = join(BASE_DIRECTORY, file);

        if (!fs.existsSync(dest) && fs.statSync(src).isFile()) {
          fs.copyFileSync(src, dest);
          // Preserve original permissions (wallet.json is 0600)
          const { mode } = fs.statSync(src);
          fs.chmodSync(dest, mode);
        }
      }
    },
    e => ({
      cause: 'migration_failed' as const,
      message: `Failed to migrate: ${e instanceof Error ? e.message : String(e)}`,
    })
  );

  if (result.isErr()) {
    console.error(
      `[agentcash] Warning: failed to migrate files from ${LEGACY_DIRECTORY} to ${BASE_DIRECTORY}. ` +
        `Your wallet may still be at ${join(LEGACY_DIRECTORY, 'wallet.json')} — copy it manually to ${join(BASE_DIRECTORY, 'wallet.json')}. ` +
        `Error: ${result.error.message}`
    );
  }
}

let initialized = false;

/**
 * Ensure the base directory exists and legacy files are migrated.
 * Runs once on first call; safe to call repeatedly.
 * Throws on failure — callers that need the filesystem (wallet, state)
 * should let this propagate. Optional consumers (logging) should
 * catch and degrade on their own.
 */
function ensureBaseDir(): void {
  if (initialized) return;

  if (!fs.existsSync(BASE_DIRECTORY)) {
    fs.mkdirSync(BASE_DIRECTORY, { recursive: true });
  }

  migrateFromLegacy();
  initialized = true;
}

export const configFile = (name: `${string}.${string}`) => {
  ensureBaseDir();
  const filePath = join(BASE_DIRECTORY, name);
  return filePath;
};
